const response = $.steps.listEmails.response || {};
const messages = response.data?.messages || response.messages || [];
let emailData = '';
const emailCount = Math.min(messages.length, 10);

messages.slice(0, 10).forEach(function(msg, i) {
  const headers = msg.payload?.headers || [];
  let subject = '';
  let from = '';
  let date = '';
  headers.forEach(function(h) {
    if (h.name === 'Subject') subject = h.value || '';
    if (h.name === 'From') from = h.value || '';
    if (h.name === 'Date') date = h.value || '';
  });
  const snippet = msg.snippet || '';
  emailData += '=== EMAIL ' + (i + 1) + ' ===\n';
  emailData += 'From: ' + from + '\n';
  emailData += 'Subject: ' + subject + '\n';
  emailData += 'Date: ' + date + '\n';
  emailData += 'Snippet: ' + snippet + '\n\n';
});

return { emailData: emailData, emailCount: emailCount };

const data = $.steps.extractEmails.output;

let prompt = 'You are an email analysis specialist. Analyze the following batch of emails and provide structured insights.

';
prompt += 'EMAILS TO ANALYZE: ' + data.emailCount + '

';
prompt += data.emailData + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Categorize each email (newsletter, personal, transactional, promotional, important, spam)
';
prompt += '- Extract key action items from emails that require response
';
prompt += '- Identify the most important emails
';
prompt += '- Provide an overall inbox summary

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "inboxSummary": "2-3 sentence overview of the inbox",
';
prompt += '  "emails": [
';
prompt += '    { "index": 1, "from": "sender", "subject": "subject", "category": "category", "priority": "high|medium|low", "actionRequired": true, "actionItem": "what to do", "summary": "1 sentence" }
';
prompt += '  ],
';
prompt += '  "actionItems": ["action 1", "action 2"],
';
prompt += '  "highPriorityCount": 0,
';
prompt += '  "categories": { "newsletter": 0, "personal": 0, "transactional": 0, "promotional": 0, "important": 0 }
';
prompt += '}';
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { inboxSummary: raw.slice(0, 300), emails: [], actionItems: [], highPriorityCount: 0, categories: {} }; }

const ai = $.steps.parseAI.output;
const rows = [];
const emails = ai.emails || [];
emails.forEach(function(e) {
  rows.push([
    String(e.index || ''),
    e.from || '',
    e.subject || '',
    e.category || '',
    e.priority || '',
    e.actionRequired ? 'Yes' : 'No',
    e.actionItem || '',
    e.summary || ''
  ]);
});
return { rows: rows, title: $.input.spreadsheetName };

const ai = $.steps.parseAI.output;
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Email Analysis Report', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: (ai.inboxSummary || 'Analysis complete.').slice(0, 1800) } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Emails Analyzed:*\n' + ((ai.emails || []).length) },
  { type: 'mrkdwn', text: '*High Priority:*\n' + (ai.highPriorityCount || 0) }
] });
blocks.push({ type: 'divider' });
const actions = ai.actionItems || [];
if (actions.length > 0) {
  let actionText = '*Action Items:*\n';
  actions.slice(0, 8).forEach(function(a, i) { actionText += (i + 1) + '. ' + a + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: actionText.slice(0, 1800) } });
}
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Data saved to Google Sheets | Powered by Gmail + Claude AI' }] });
const fallbackText = 'Email Analysis: ' + ((ai.emails || []).length) + ' emails analyzed, ' + (ai.highPriorityCount || 0) + ' high priority';
return { blocks, fallbackText };
